sys_script.script:
(function executeRule(current, previous) {

        gs.info("BR STARTED");

        var ticketStatus =
            current.getValue('ticket_status');
        var mainWorkspaceStatus =
            current.getValue('workspace_status');

        gs.info("Workspace value: " + current.workspace);

        if (!current.workspace) {
            gs.info("Workspace is EMPTY");
            return;
        }

        //Workspace option table
        var workspaceGR = new GlideRecord('x_451445_wrm_workspace_options');


        if (workspaceGR.get(current.workspace)) {

                gs.info("Record exists: " + workspaceGR.number);

                if (ticketStatus == 'open' && mainWorkspaceStatus == 'in_maintenance') {
                    workspaceGR.status = 'under_maintenance';

                } else if (ticketStatus == 'closed' && mainWorkspaceStatus == 'available') {
                    workspaceGR.status = 'available';

                } else if (ticketStatus == 'closed' && mainWorkspaceStatus == 'decommissioned') {
                    workspaceGR.status = 'decommissioned';

                }

                workspaceGR.update();
                gs.info('Yas: update status to ' + workspaceGR.status);

            } else {
                gs.info("No matching workspace found");
            }

        })(current, previous);
